-- HeartConnect seed profiles: 100 explicit direct inserts.
--
-- This script intentionally uses plain SQL only:
-- 1. Reset existing seed/demo rows so the final counts are deterministic.
-- 2. Insert auth.users rows.
-- 3. Insert matching public.profiles rows with the same ids.
-- 4. Insert public.profile_photos rows.
--
-- It does not create likes, matches, messages, or fake engagement.

BEGIN;

DELETE FROM public.profile_photos
WHERE user_id IN (
  SELECT id FROM public.profiles WHERE is_demo_profile = true
);

DELETE FROM public.profiles
WHERE is_demo_profile = true;

DELETE FROM auth.users
WHERE email LIKE 'seed_%@heartconnect.local'
   OR email LIKE '%@demo.heartconnect.local';

INSERT INTO auth.users (
  instance_id,
  id,
  aud,
  role,
  email,
  encrypted_password,
  email_confirmed_at,
  created_at,
  updated_at,
  raw_app_meta_data,
  raw_user_meta_data,
  is_super_admin,
  confirmation_token,
  email_change,
  email_change_token_new,
  recovery_token
)
